package DailtAssignment2;

public class Program1 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		char num='A';
		int value=num;
		
		char num1='a';
		int value1=num1;
		
		char num2='0';
		int value2=num2;
		
		char num3='@';
		int value3=num3;
		
		
		System.out.println("ASCII Value of A = "+value);
		System.out.println("ASCII Value of a = "+value1);
		System.out.println("ASCII Value of 0 = "+value2);
		System.out.println("ASCII Value of @ = "+value3);
		

	}

}
